## MUDANÇA 4 — Projeções: mudar título (HTML)

No dashboard.html, dentro de `#fin-pane-projecoes`, mude:
```html
<h3 class="fin-proj-title">Próximos 3 Meses (Itens Recorrentes)</h3>
<p class="fin-proj-sub">Apenas itens marcados como <span class="cyan">Recorrente</span> — previsibilidade de caixa fixo</p>
```
Para:
```html
<h3 class="fin-proj-title">Projeção Mensal — Jan a Dez/2026</h3>
<p class="fin-proj-sub">Baseado no <span class="cyan">Raio-X</span> — ganhos e gastos fixos mês a mês</p>
```

---

## MUDANÇA 5 — JS: reescrever atualizarProjecoes()

No financeiro.js, a função `atualizarProjecoes()` começa na linha ~705 e usa TRANSACOES filtradas por recorrentes. Precisa ser COMPLETAMENTE REESCRITA para usar RAIOX e mostrar todos os 12 meses de 2026.

Substitua o corpo da função por:
```javascript
  function atualizarProjecoes() {
    var grid = document.getElementById('fin-proj-grid');
    if (!grid) return;
    var totais = raixoTotaisMensais();
    grid.innerHTML = MESES_LABEL.map(function(label, i) {
      var entrada = totais.receitas[i];
      var saida   = totais.fixas[i] + totais.variaveis[i];
      var saldo   = totais.saldo[i];
      var cls     = saldo >= 0 ? 'fin-proj-positive' : 'fin-proj-negative';
      var sinal   = saldo >= 0 ? '+' : '-';
      var isPast  = (i + 1) <= mesSelecionado;
      return '<div class="fin-proj-card' + (isPast ? ' fin-proj-past' : '') + '">' +
        '<div class="fin-proj-mes">' + label + '/2026' + (isPast ? ' <span class="fin-proj-real">✓</span>' : '') + '</div>' +
        '<div class="fin-proj-row"><span>Ganhos</span><span class="fin-val-positive">' + fmt(entrada) + '</span></div>' +
        '<div class="fin-proj-row"><span>Gastos</span><span class="fin-val-negative">-' + fmt(saida) + '</span></div>' +
        '<div class="fin-proj-divider"></div>' +
        '<div class="fin-proj-row fin-proj-saldo"><span>Saldo</span><span class="' + cls + '">' + sinal + ' ' + fmt(Math.abs(saldo)) + '</span></div>' +
      '</div>';
    }).join('');
    // Atualizar chips do acumulado
    renderGraficoLinha();
  }
```

---

## MUDANÇA 6 — JS: reescrever renderMilhaoChart() com eixo Idade

No financeiro.js, a função `renderMilhaoChart()` começa na linha ~872. Precisa ser reescrita para:
- Eixo X = idade (em anos, ex: "23 anos", "24 anos", ...)
- Eixo Y = patrimônio
- Tooltip mostra: Patrimônio e Idade

A data de nascimento já está no calcularMilhao(): `var nascimento = new Date(2001, 3, 5);`

Reescreva a função `renderMilhaoChart(n, aporte, patrimonio, taxa, meta)`:

```javascript
  function renderMilhaoChart(n, aporte, patrimonio, taxa, meta) {
    var canvas = document.getElementById('mil-chart-evolucao');
    if (!canvas || typeof Chart === 'undefined') return;

    var nascimento = new Date(2001, 3, 5);
    var hoje = new Date();

    // Gerar pontos a cada step meses
    var pontos = [], labels = [], idadesAnos = [], idadesMeses = [];
    var fv = patrimonio;
    var step = Math.max(1, Math.floor(n / 40)); // max 40 pontos
    for (var i = 0; i <= n; i++) {
      if (i % step === 0 || i === n) {
        var dataPoint = new Date(hoje);
        dataPoint.setMonth(dataPoint.getMonth() + i);
        var diffMs = dataPoint - nascimento;
        var idadeF = diffMs / (1000 * 60 * 60 * 24 * 365.25);
        var anos   = Math.floor(idadeF);
        var meses  = Math.floor((idadeF - anos) * 12);
        labels.push(anos + ' anos');
        idadesAnos.push(anos);
        idadesMeses.push(meses);
        pontos.push(parseFloat(fv.toFixed(2)));
      }
      fv = fv * (1 + taxa) + aporte;
    }

    if (chartMilhao) chartMilhao.destroy();
    chartMilhao = new Chart(canvas, {
      type: 'line',
      data: {
        labels: labels,
        datasets: [{
          label: 'Patrimônio',
          data: pontos,
          borderColor: '#00e5ff',
          backgroundColor: 'rgba(0,229,255,0.08)',
          borderWidth: 2,
          pointRadius: 0,
          pointHoverRadius: 5,
          pointHoverBackgroundColor: '#00e5ff',
          tension: 0.4,
          fill: true,
        },{
          label: 'Meta',
          data: Array(labels.length).fill(meta),
          borderColor: 'rgba(105,240,174,0.5)',
          borderWidth: 1,
          borderDash: [6,4],
          pointRadius: 0,
          fill: false,
        }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        interaction: { mode: 'index', intersect: false },
        plugins: {
          legend: { labels: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, boxWidth: 12 } },
          tooltip: {
            callbacks: {
              title: function(items) {
                var idx = items[0].dataIndex;
                return idadesAnos[idx] + ' anos e ' + idadesMeses[idx] + ' meses';
              },
              label: function(ctx) {
                if (ctx.datasetIndex === 0) {
                  return ' Patrimônio: R$ ' + ctx.raw.toLocaleString('pt-BR', {minimumFractionDigits:2});
                }
                return ' Meta: R$ ' + ctx.raw.toLocaleString('pt-BR', {minimumFractionDigits:2});
              }
            }
          }
        },
        scales: {
          x: {
            ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 10 }, maxTicksLimit: 10 },
            grid: { color: 'rgba(0,229,255,0.06)' },
            title: { display: true, text: 'Idade', color: '#546e7a', font: { family: 'Rajdhani', size: 12 } }
          },
          y: {
            ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, callback: function(v){ return 'R$ '+(v/1000).toFixed(0)+'K'; } },
            grid: { color: 'rgba(0,229,255,0.06)' },
            title: { display: true, text: 'Patrimônio', color: '#546e7a', font: { family: 'Rajdhani', size: 12 } }
          }
        }
      }
    });
  }
```

---

## MUDANÇA 7 — JS: remover código de lançamentos

No financeiro.js, remova/limpe o seguinte:

1. Em `initFinanceiro()` (perto da linha 198): remova os blocos:
```javascript
    // Lançamentos
    var btnAdd = document.getElementById('fin-add-btn');
    if (btnAdd) btnAdd.addEventListener('click', adicionarLancamento);

    var prevBtn = document.getElementById('fin-mes-prev');
    var nextBtn = document.getElementById('fin-mes-next');
    if (prevBtn) prevBtn.addEventListener('click', function(){ navegarMes(-1); });
    if (nextBtn) nextBtn.addEventListener('click', function(){ navegarMes(1); });

    var dataInput = document.getElementById('fin-data');
    if (dataInput) dataInput.value = new Date().toISOString().split('T')[0];
```
E também remova dentro do tab click handler a referência ao tab 'lancamentos' se houver.

2. Em `atualizarTudo()` (linha ~229): remova a chamada `atualizarTabela();`

3. Remova as funções completas:
   - `atualizarTabela()` (função que popula `fin-tbody`)
   - `adicionarLancamento()` 
   - `navegarMes(dir)`
   - `atualizarMesLabel()`
   - `flash(msg, tipo)` — só remova se não for usada em nenhum outro lugar (verifique com Grep)

---

## ATENÇÃO
- Leia os trechos antes de editar para pegar a string exata
- Faça um edit de cada vez — não tente editar regiões sobrepostas
- Use Grep para localizar linhas exatas antes de editar
- Após cada mudança complexa, verifique com Grep se ficou correto
- Não quebre a estrutura do IIFE `(function() { ... })();`

Execute todas as mudanças e confirme ao final o que foi feito.

